#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 100005
#define MAX_M 200005
#define MAX_Q 100005
#define INF INT_MAX

int n, m, q;
int u[MAX_M], v[MAX_M], c[MAX_M];
int dist[MAX_N];
int queue[MAX_N];
int front, rear;

void bfs(int start) {
    for (int i = 1; i <= n; i++) {
        dist[i] = INF;
    }
    dist[start] = 0;
    front = rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int current = queue[front++];
        for (int i = 0; i < m; i++) {
            if (u[i] == current || v[i] == current) {
                int next = (u[i] == current) ? v[i] : u[i];
                if (dist[next] > dist[current] + c[i]) {
                    dist[next] = dist[current] + c[i];
                    queue[rear++] = next;
                }
            }
        }
    }
}

int main() {
    scanf("%d %d", &n, &m);
    for (int i = 0; i < m; i++) {
        scanf("%d %d %d", &u[i], &v[i], &c[i]);
    }
    scanf("%d", &q);
    for (int i = 0; i < q; i++) {
        int start, end;
        scanf("%d %d", &start, &end);
        bfs(start);
        printf("%d\n", dist[end]);
    }
    return 0;
}

