#include <iostream>
#include <queue>
#include <vector>
#include <limits>
using namespace std;

const int MAX_N = 100005;
const int MAX_M = 200005;
const int MAX_Q = 100005;
const int INF = numeric_limits<int>::max();

int n, m, q;
vector<pair<int, int>> adj[MAX_N];

void bfs(int start, int dist[]) {
    for (int i = 1; i <= n; i++) {
        dist[i] = INF;
    }
    dist[start] = 0;
    queue<int> q;
    q.push(start);
    while (!q.empty()) {
        int current = q.front();
        q.pop();
        for (auto &edge : adj[current]) {
            int next = edge.first;
            int weight = edge.second;
            if (dist[next] > dist[current] + weight) {
                dist[next] = dist[current] + weight;
                q.push(next);
            }
        }
    }
}

int main() {
    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        int u, v, c;
        cin >> u >> v >> c;
        adj[u].push_back({v, c});
        adj[v].push_back({u, c});
    }
    cin >> q;
    for (int i = 0; i < q; i++) {
        int start, end;
        cin >> start >> end;
        int dist[MAX_N];
        bfs(start, dist);
        cout << dist[end] << endl;
    }
    return 0;
}

