import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    static final int MAX_N = 100005;
    static final int MAX_M = 200005;
    static final int MAX_Q = 100005;
    static final int INF = Integer.MAX_VALUE;

    static int n, m, q;
    static int[][] adj;
    static int[] dist;

    public static void bfs(int start) {
        for (int i = 1; i <= n; i++) {
            dist[i] = INF;
        }
        dist[start] = 0;
        Queue<Integer> q = new LinkedList<>();
        q.add(start);
        while (!q.isEmpty()) {
            int current = q.poll();
            for (int i = 0; i < adj[current].length; i++) {
                int next = adj[current][i][0];
                int weight = adj[current][i][1];
                if (dist[next] > dist[current] + weight) {
                    dist[next] = dist[current] + weight;
                    q.add(next);
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        m = sc.nextInt();
        adj = new int[n + 1][];
        for (int i = 0; i < m; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            int c = sc.nextInt();
            if (adj[u] == null) {
                adj[u] = new int[][] {{v, c}};
            } else {
                int[][] temp = new int[adj[u].length + 1][];
                System.arraycopy(adj[u], 0, temp, 0, adj[u].length);
                temp[adj[u].length] = new int[] {v, c};
                adj[u] = temp;
            }
            if (adj[v] == null) {
                adj[v] = new int[][] {{u, c}};
            } else {
                int[][] temp = new int[adj[v].length + 1][];
                System.arraycopy(adj[v], 0, temp, 0, adj[v].length);
                temp[adj[v].length] = new int[] {u, c};
                adj[v] = temp;
            }
        }
        q = sc.nextInt();
        dist = new int[n + 1];
        for (int i = 0; i < q; i++) {
            int start = sc.nextInt();
            int end = sc.nextInt();
            bfs(start);
            System.out.println(dist[end]);
        }
    }
}

